UPDATE agent_route_knowledge SET description =
E'Карымшинские термальные источники (52.841°N, 158.152°E) — термальный кластер в 80 км от Петропавловска по дороге на Мутновский и Горелый. Удобная остановка для отдыха при возвращении с вулканических туров.\n\nВода +36–45°С, хлоридно-натриевая слабоминерализованная. Несколько природных купелей разной температуры обустроены деревянными настилами и раздевалкой. Чистая, прозрачная вода с лёгким минеральным привкусом — без сероводородного запаха.\n\nОсобенно хороши в вечернее время: горячая вода под звёздным небом с видом на силуэты вулканов. Входят в большинство туров к Мутновскому как обязательная остановка для купания после трекинга.'
