UPDATE agent_route_knowledge SET description =
E'Малые Банные горячие источники (52.856°N, 157.785°E) — хлоридно-натриевые высококремниевые термы с уникальным составом воды: содержание кремниевой кислоты (SiO₂) достигает 100 мг/л — рекордный показатель для камчатских источников. Кремниевые воды считаются одними из наиболее полезных для кожных заболеваний и опорно-двигательного аппарата.\n\nТемпература +50–65°С у выхода, в купелях +38–44°С. Состав схож с Большими Банными, но концентрация кремниевой кислоты вдвое выше. Белые кремниевые натёки на камнях — визитная карточка этого места.\n\nРасположены в 5 км от Больших Банных. Доступны пешком или на вездеходе. Малолюдное место с дикой природой.'
WHERE id = 'fef47016-0772-408f-bc6d-6c46fa5e1ae1';

