UPDATE agent_route_knowledge SET description =
E'Краеведческие горячие источники (53.555°N, 158.821°E) — сероводородные термы в Налычевском парке с необычным составом воды: H₂S 2–5 мг/л придаёт воде лёгкий запах серы и желтоватый цвет. Температура +45–55°С, pH 6–7.\n\nСероводородные воды особенно ценятся в бальнеологии: применяются при болезнях суставов, кожи и периферической нервной системы. Белые и светло-жёлтые травертиновые натёки вдоль ручья — характерная картина активной геохимии.\n\nРасположены в северной части Налычевского парка. Менее посещаемы, чем Таловские, — для тех, кто ищет уединение и интерес к минеральному разнообразию камчатских вод.'
