UPDATE agent_route_knowledge SET description =
E'Озеро Начикинское (53.020°N, 157.826°E) — уникальный природный водоём, питаемый термальными хлоридно-натриевыми источниками. Температура воды в озере +28–34°С круглый год — тёплое даже зимой, когда поверхность остаётся незамёрзшей при морозе за окном.\n\nОзеро не замерзает с ноября по март — феноменальное зрелище: открытая тёплая вода в зимней тундре, над которой клубится пар. Водоплавающие птицы держатся здесь даже в январе. Состав воды мягкий, без резких запахов — подходит для долгого купания.\n\nРасположено в 3 км от Начикинских термальных источников. Добраться из ПКК на обычном автомобиле через Паратунку (~80 км). Хорошо сочетается с посещением Начикинских источников и санатория «Начика».'
WHERE id = '1ac51fcf-3596-4df5-a066-9da9085fa0f9';
